changeSet.sql:
CREATE TABLE chat_room ( id VARCHAR(36) PRIMARY KEY, chat_id VARCHAR(36) NOT NULL, sender_id VARCHAR(64), recipient_id VARCHAR(64), candidate_id INTEGER, employer_id INTEGER, candidate_name VARCHAR(255), employer_name VARCHAR(255), candidate_avatar_url TEXT, employer_avatar_url TEXT, vacancy_public_id VARCHAR(255), vacancy_title VARCHAR(255), resume_id BIGINT, resume_profession VARCHAR(255), application_id BIGINT, last_message TEXT, last_message_at TIMESTAMP, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_chat_room_candidate FOREIGN KEY (candidate_id) REFERENCES users(id) ON DELETE SET NULL, CONSTRAINT fk_chat_room_employer FOREIGN KEY (employer_id) REFERENCES users(id) ON DELETE SET NULL, CONSTRAINT fk_chat_room_resume FOREIGN KEY (resume_id) REFERENCES candidate_resume(id) ON DELETE SET NULL, CONSTRAINT fk_chat_room_application FOREIGN KEY (application_id) REFERENCES application(id) ON DELETE SET NULL );
CREATE INDEX idx_chat_room_chat_id ON chat_room (chat_id); CREATE INDEX idx_chat_room_candidate_id ON chat_room (candidate_id); CREATE INDEX idx_chat_room_employer_id ON chat_room (employer_id); CREATE INDEX idx_chat_room_application_id ON chat_room (application_id); CREATE UNIQUE INDEX ux_chat_room_application_id ON chat_room (application_id) WHERE application_id IS NOT NULL; CREATE UNIQUE INDEX ux_chat_room_invite_target ON chat_room (employer_id, candidate_id, vacancy_public_id, resume_id) WHERE application_id IS NULL;
CREATE TABLE chat_message ( id VARCHAR(36) PRIMARY KEY, chat_id VARCHAR(36) NOT NULL, sender_id VARCHAR(64) NOT NULL, recipient_id VARCHAR(64) NOT NULL, sender_name VARCHAR(255), recipient_name VARCHAR(255), content TEXT NOT NULL, timestamp TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, status VARCHAR(32) NOT NULL DEFAULT 'RECEIVED' );
CREATE INDEX idx_chat_message_chat_id ON chat_message (chat_id); CREATE INDEX idx_chat_message_recipient_status ON chat_message (recipient_id, status); CREATE INDEX idx_chat_message_timestamp ON chat_message (timestamp);
CREATE TABLE chat_notification ( id VARCHAR(36) PRIMARY KEY, sender_id VARCHAR(64), sender_name VARCHAR(255) );
